async function decode(e,o=8e3){const n=new AudioContext({sampleRate:o}),t=n.decodeAudioData(e);return t.finally(()=>n.close()),t}function createBuffer(o,e){if((o="number"==typeof o[0]?[o]:o)[0].some(e=>1<e||e<-1)){const n=Math.max(...o[0]);o=o.map(e=>e.map(e=>e/n))}return{length:o[0].length,duration:e,numberOfChannels:o.length,sampleRate:o[0].length/e,getChannelData:e=>o?.[e],copyFromChannel:AudioBuffer.prototype.copyFromChannel,copyToChannel:AudioBuffer.prototype.copyToChannel}}const Decoder={decode:decode,createBuffer:createBuffer};export default Decoder;